const webhook = $('Article Feedback Webhook').first().json ?? {};
const body = webhook.body ?? webhook;
const articleKey = String(body.articleKey ?? '').trim();
const articleUrl = String(body.articleUrl ?? '').trim();
const decision = String(body.decision ?? '').trim().toLocaleLowerCase('ja-JP');
const requestedReasonCode = String(body.reasonCode ?? '').trim().toLocaleLowerCase('ja-JP');
const source = String(body.source ?? '').trim();
const validDecisions = new Set(['approved', 'rejected']);
const validReasons = new Set(['suspicious_source', 'irrelevant', 'unavailable', 'outdated']);
const articles = $input.all().map((item) => item.json ?? {});
const article = articles.find((item) => String(item.article_key ?? '').trim() === articleKey);
const text = (value, field, maximum = 500) => {
  const result = String(value ?? '').trim();
  if (result.length > maximum) throw new Error(field + ' is too long.');
  return result;
};
const domain = (value) => {
  const result = text(value, 'sourceDomain', 253).toLocaleLowerCase('ja-JP').replace(/^www\./, '');
  if (result && !/^[a-z0-9.-]+$/.test(result)) throw new Error('sourceDomain is invalid.');
  return result;
};
if (source !== 'talent-dashboard') throw new Error('This webhook only accepts the local Talent Index dashboard.');
if (!articleKey) throw new Error('articleKey is required.');
if (!validDecisions.has(decision)) throw new Error('decision must be approved or rejected.');
if (decision === 'rejected' && !validReasons.has(requestedReasonCode)) throw new Error('reasonCode is invalid.');
if (decision === 'approved' && requestedReasonCode && requestedReasonCode !== 'approved') throw new Error('reasonCode is invalid for an approved article.');
if (!article) throw new Error('Unknown articleKey.');
if (articleUrl && String(article.url ?? '').trim() !== articleUrl) throw new Error('articleUrl does not match articleKey.');

const reasonCode = decision === 'approved' ? 'approved' : requestedReasonCode;
const sourceDomain = decision === 'rejected' && reasonCode === 'suspicious_source' ? domain(body.sourceDomain) : '';
const publisherLabel = decision === 'rejected' && reasonCode === 'suspicious_source'
  ? text(body.publisherLabel, 'publisherLabel', 200).toLocaleLowerCase('ja-JP')
  : '';
const titleSignature = decision === 'rejected' && reasonCode === 'irrelevant'
  ? text(body.titleSignature, 'titleSignature', 500).toLocaleLowerCase('ja-JP')
  : '';
return [{
  json: {
    article_key: articleKey, article_url: String(article.url ?? '').trim(),
    is_rejected: decision === 'rejected', reason_code: reasonCode,
    source_domain: sourceDomain, publisher_label: publisherLabel,
    title_signature: titleSignature, reviewed_at: new Date().toISOString(), review_source: source,
  },
}];

const feedback = $('Validate Article Feedback').first().json;
return [{
  json: {
    accepted: true,
    articleKey: feedback.article_key,
    decision: feedback.is_rejected ? 'rejected' : 'approved',
    reasonCode: feedback.reason_code,
    reviewedAt: feedback.reviewed_at,
  },
}];
